{
  "name": "subscription-temporal",
  "version": "1.0.0",
  "description": "Subscription workflow with Temporal Cloud",
  "main": "lib/client.js",
  "scripts": {
    "build": "tsc --build",
    "start": "npm run build && node lib/start.js"
  },
  "dependencies": {
    "@temporalio/activity": "^1.11.6",
    "@temporalio/client": "^1.11.6",
    "@temporalio/worker": "^1.11.6",
    "@temporalio/workflow": "^1.11.6"
  },
  "devDependencies": {
    "typescript": "^5.4.5",
    "@types/node": "^20.12.12"
  }
}

import {
  defineSignal,
  defineQuery,
  setHandler,
  condition,
  sleep,
  proxyActivities,
} from '@temporalio/workflow';
import type { Activities } from './activities';

// Define signals
export const upgradeSignal = defineSignal<[string]>('upgrade');
export const cancelSignal = defineSignal('cancel');

// Define query
export const getStatusQuery = defineQuery<{
  tier: string;
  billings: number;
  cancelled: boolean;
}>('getStatus');

// Proxy activities with a reasonable timeout
const { chargeCard } = proxyActivities<Activities>({
  startToCloseTimeout: '30 seconds',
});

export interface SubscriptionInput {
  userId: string;
  tier: string;
}

export interface SubscriptionResult {
  billings: number;
  finalTier: string;
  cancelled: boolean;
}

export async function SubscriptionWorkflow(
  input: SubscriptionInput
): Promise<SubscriptionResult> {
  const { userId } = input;

  // Mutable state
  let tier = input.tier;
  let billings = 0;
  let cancelled = false;

  // Register signal handlers
  setHandler(upgradeSignal, (newTier: string) => {
    tier = newTier;
  });

  setHandler(cancelSignal, () => {
    cancelled = true;
  });

  // Register query handler
  setHandler(getStatusQuery, () => ({
    tier,
    billings,
    cancelled,
  }));

  // Run up to 12 billing periods
  for (let period = 0; period < 12; period++) {
    // Check for cancellation before starting a new period
    if (cancelled) {
      break;
    }

    // Wait between periods (skip sleep before the very first period)
    if (period > 0) {
      // Sleep for 2000ms but also wake up early if cancelled
      await Promise.race([
        sleep(2000),
        condition(() => cancelled),
      ]);

      // If cancelled during sleep, exit without charging
      if (cancelled) {
        break;
      }
    }

    // Charge card for current period using the current tier
    await chargeCard(userId, tier);
    billings++;
  }

  return {
    billings,
    finalTier: tier,
    cancelled,
  };
}

import * as fs from 'fs';
import * as path from 'path';

const WORKSPACE_DIR = '/workspace';
const CHARGES_LOG = path.join(WORKSPACE_DIR, 'charges.log');

export async function chargeCard(userId: string, tier: string): Promise<void> {
  // Ensure /workspace directory exists
  if (!fs.existsSync(WORKSPACE_DIR)) {
    fs.mkdirSync(WORKSPACE_DIR, { recursive: true });
  }

  // Append a line: <userId>:<tier>\n
  const line = `${userId}:${tier}\n`;
  fs.appendFileSync(CHARGES_LOG, line, { encoding: 'utf8' });
}

export type Activities = {
  chargeCard: typeof chargeCard;
};

import { Worker, NativeConnection } from '@temporalio/worker';
import * as activities from './activities';
import * as path from 'path';

async function main() {
  const apiKey = process.env.TEMPORAL_API_KEY;
  const address = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE;

  if (!apiKey || !address || !namespace) {
    throw new Error(
      'Missing required environment variables: TEMPORAL_API_KEY, TEMPORAL_ADDRESS, TEMPORAL_NAMESPACE'
    );
  }

  // Connect to Temporal Cloud using API key + TLS
  const connection = await NativeConnection.connect({
    address,
    tls: true,
    apiKey,
  });

  const worker = await Worker.create({
    connection,
    namespace,
    taskQueue: 'sub-ts',
    // Point to the compiled workflow bundle
    workflowsPath: path.resolve(__dirname, 'workflow'),
    activities,
  });

  console.log('Worker started, polling task queue: sub-ts');

  // Run until cancelled
  await worker.run();
}

main().catch((err) => {
  console.error('Worker failed:', err);
  process.exit(1);
});

import { Connection, Client } from '@temporalio/client';
import { SubscriptionWorkflow, upgradeSignal, cancelSignal, getStatusQuery } from './workflow';

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function main() {
  const apiKey = process.env.TEMPORAL_API_KEY;
  const address = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE;
  const runId = process.env.ZEALT_RUN_ID;

  if (!apiKey || !address || !namespace) {
    throw new Error(
      'Missing required environment variables: TEMPORAL_API_KEY, TEMPORAL_ADDRESS, TEMPORAL_NAMESPACE'
    );
  }

  if (!runId) {
    throw new Error('Missing required environment variable: ZEALT_RUN_ID');
  }

  const workflowId = `sub-${runId}`;

  // Connect to Temporal Cloud using API key + TLS
  const connection = await Connection.connect({
    address,
    tls: true,
    apiKey,
  });

  const client = new Client({
    connection,
    namespace,
  });

  console.log(`Starting SubscriptionWorkflow with id: ${workflowId}`);

  // 1. Start the workflow
  const handle = await client.workflow.start(SubscriptionWorkflow, {
    taskQueue: 'sub-ts',
    workflowId,
    args: [{ userId: 'u1', tier: 'basic' }],
  });

  console.log(`Workflow started: ${workflowId}`);

  // 2. After 1 second, send upgrade signal
  await sleep(1000);
  await handle.signal(upgradeSignal, 'premium');
  console.log('Sent upgrade signal: premium');

  // 3. After another 2 seconds (~3s since start), query status
  await sleep(2000);
  const status = await handle.query(getStatusQuery);
  console.log('Status query result:', status);

  // 4. After another 2 seconds (~5s since start), send cancel signal
  await sleep(2000);
  await handle.signal(cancelSignal);
  console.log('Sent cancel signal');

  // 5. Await the final result
  const result = await handle.result();
  console.log(`Final result: ${JSON.stringify(result)}`);
}

main().catch((err) => {
  console.error('Client failed:', err);
  process.exit(1);
});

import { spawn } from 'child_process';
import * as path from 'path';

async function main() {
  const workerScript = path.resolve(__dirname, 'worker.js');
  const clientScript = path.resolve(__dirname, 'client.js');

  // Start the worker in the background
  const workerProcess = spawn(process.execPath, [workerScript], {
    env: process.env,
    stdio: ['ignore', 'pipe', 'pipe'],
  });

  workerProcess.stdout?.on('data', (data: Buffer) => {
    process.stdout.write(`[worker] ${data}`);
  });
  workerProcess.stderr?.on('data', (data: Buffer) => {
    process.stderr.write(`[worker] ${data}`);
  });

  // Give the worker a moment to connect before starting the client
  await new Promise((resolve) => setTimeout(resolve, 3000));

  // Run the client
  const clientProcess = spawn(process.execPath, [clientScript], {
    env: process.env,
    stdio: ['ignore', 'pipe', 'pipe'],
  });

  clientProcess.stdout?.on('data', (data: Buffer) => {
    process.stdout.write(data);
  });
  clientProcess.stderr?.on('data', (data: Buffer) => {
    process.stderr.write(data);
  });

  // Wait for the client to finish
  const exitCode: number = await new Promise((resolve) => {
    clientProcess.on('close', (code: number | null) => {
      resolve(code ?? 0);
    });
  });

  // Kill the worker now that the client is done
  workerProcess.kill('SIGTERM');

  // Wait for worker to exit
  await new Promise<void>((resolve) => {
    workerProcess.on('close', () => resolve());
    // Give it a few seconds to clean up, then force-resolve
    setTimeout(resolve, 5000);
  });

  process.exit(exitCode);
}

main().catch((err) => {
  console.error('Start script failed:', err);
  process.exit(1);
});

